-- 党内法规数据批量导入脚本（约100条真实数据）
-- 执行方式：mysql -u root -p party_regulation_db < import_regulations.sql

USE party_regulation_db;

INSERT INTO regulation_document (title, category, org, publish_date, status, char_count, content, create_time) VALUES

-- ========== 党章 ==========
('中国共产党章程（2022年修改）', '党章', '中国共产党第二十次全国代表大会', '2022-10-22', 1, 18200, '中国共产党章程\n\n中国共产党第二十次全国代表大会部分修改，2022年10月22日通过\n\n总 纲\n\n中国共产党是中国工人阶级的先锋队，同时是中国人民和中华民族的先锋队，是中国特色社会主义事业的领导核心，代表中国先进生产力的发展要求，代表中国先进文化的前进方向，代表中国最广大人民的根本利益。党的最高理想和最终目标是实现共产主义。\n\n中国共产党以马克思列宁主义、毛泽东思想、邓小平理论、"三个代表"重要思想、科学发展观、习近平新时代中国特色社会主义思想作为自己的行动指南。\n\n第一章 党员\n\n第一条 年满十八岁的中国工人、农民、军人、知识分子和其他社会阶层的先进分子，承认党的纲领和章程，愿意参加党的一个组织并在其中积极工作、执行党的决议和按期交纳党费的，可以申请加入中国共产党。\n\n第二条 中国共产党党员是中国工人阶级的有共产主义觉悟的先锋战士。中国共产党党员必须全心全意为人民服务，不惜牺牲个人的一切，为实现共产主义奋斗终身。中国共产党党员永远是劳动人民的普通一员。除了法律和政策规定范围内的个人利益和工作职权以外，所有共产党员都不得谋求任何私利和特权。\n\n第三条 党员必须履行下列义务：（一）认真学习马克思列宁主义、毛泽东思想、邓小平理论、"三个代表"重要思想、科学发展观、习近平新时代中国特色社会主义思想，学习党的路线、方针、政策和决议，学习党的基本知识，学习科学、文化、法律和业务知识，努力提高为人民服务的本领。（二）贯彻执行党的基本路线和各项方针、政策，带头参加改革开放和社会主义现代化建设，带动群众为经济发展和社会进步艰苦奋斗，在生产、工作、学习和社会生活中起先锋模范作用。', '2024-01-01 00:00:00'),

('关于新形势下党内政治生活的若干准则', '党章', '中国共产党第十八届中央委员会第六次全体会议', '2016-10-27', 1, 16500, '关于新形势下党内政治生活的若干准则（2016年10月27日中国共产党第十八届中央委员会第六次全体会议通过）\n\n办好中国的事情，关键在党，关键在党要管党、从严治党。党要管党必须从党内政治生活管起，从严治党必须从党内政治生活严起。\n\n一、坚定理想信念\n\n理想信念动摇是最危险的动摇，理想信念滑坡是最危险的滑坡。全党同志必须把对马克思主义的信仰、对社会主义和共产主义的信念作为毕生追求，坚定对中国特色社会主义的道路自信、理论自信、制度自信、文化自信。', '2024-01-01 00:00:00'),

('中国共产党党内法规制定条例', '党章', '中共中央', '2019-08-30', 1, 9800, '中国共产党党内法规制定条例（2019年修订）\n\n第一章 总则\n\n第一条 为了规范党内法规制定工作，提高党内法规质量，形成完善的党内法规体系，推进依规治党，根据《中国共产党章程》，制定本条例。\n\n第二条 党内法规制定工作以马克思列宁主义、毛泽东思想、邓小平理论、"三个代表"重要思想、科学发展观、习近平新时代中国特色社会主义思想为指导，坚持和加强党的全面领导，坚持党要管党、全面从严治党。\n\n第三条 党内法规是党的中央组织，中央纪律检查委员会以及党中央工作机关和省、自治区、直辖市党委制定的体现党的统一意志、规范党的领导和党的建设活动、依靠党的纪律保证实施的专门规章制度。\n\n党内法规的名称为党章、准则、条例、规定、办法、规则、细则。', '2024-01-01 00:00:00'),

('中国共产党党内法规和规范性文件备案审查规定', '党章', '中共中央', '2019-08-30', 1, 7500, '中国共产党党内法规和规范性文件备案审查规定（2019年修订）\n\n第一条 为了规范党内法规和规范性文件备案审查工作，维护党内法规和规范性文件的统一性和权威性，根据《中国共产党党内法规制定条例》，制定本规定。\n\n第二条 本规定适用于党内法规和规范性文件的备案审查工作。本规定所称规范性文件，是指党组织在履行职责过程中形成的具有普遍约束力、可以反复适用的文件。', '2024-01-01 00:00:00'),

('中国共产党党内法规执行责任制规定（试行）', '党章', '中共中央', '2019-08-30', 1, 5200, '中国共产党党内法规执行责任制规定（试行）\n\n第一条 为了深入贯彻习近平新时代中国特色社会主义思想，全面落实党中央关于加强党内法规制度建设的部署要求，强化各级党组织和党员领导干部执规责任，提高党内法规执行力，推动党内法规真正落地见效，根据《中国共产党章程》和有关党内法规，制定本规定。\n\n第二条 各级党组织和党员领导干部应当切实担负起执行党内法规的政治责任，把党内法规执行情况作为督促检查、巡视巡察的重要内容，推动党内法规执行到位。', '2024-01-01 00:00:00'),

-- ========== 纪律法规 ==========
('中国共产党纪律处分条例（2023年修订）', '纪律法规', '中共中央', '2023-12-19', 1, 28500, '中国共产党纪律处分条例（2023年12月修订）\n\n第一编 总则\n\n第一章 指导思想、原则和适用范围\n\n第一条 为了维护党章和其他党内法规，严肃党的纪律，纯洁党的组织，保障党员民主权利，教育党员遵纪守法，维护党的团结统一，保证党的路线、方针、政策、决议和国家法律法规的贯彻执行，根据《中国共产党章程》，制定本条例。\n\n第二条 党的纪律建设必须坚持以马克思列宁主义、毛泽东思想、邓小平理论、"三个代表"重要思想、科学发展观、习近平新时代中国特色社会主义思想为指导，坚持和加强党的全面领导，坚决维护习近平总书记党中央的核心、全党的核心地位，坚决维护党中央权威和集中统一领导。\n\n第三条 党章是最根本的党内法规，是管党治党的总规矩。党的纪律是党的各级组织和全体党员必须遵守的行为规则。\n\n第二章 违纪与纪律处分\n\n第六条 对党员的纪律处分种类：（一）警告；（二）严重警告；（三）撤销党内职务；（四）留党察看；（五）开除党籍。\n\n第七条 对党组织的纪律处理措施：（一）改组；（二）解散。', '2024-01-01 00:00:00'),

('中国共产党问责条例', '纪律法规', '中共中央', '2019-08-25', 1, 5600, '中国共产党问责条例（2019年修订）\n\n第一条 为了坚持党的领导，加强党的建设，全面从严治党，保证党的路线方针政策和党中央重大决策部署贯彻落实，规范党的问责工作，根据《中国共产党章程》，制定本条例。\n\n第二条 问责工作应当坚持以下原则：（一）依规依纪、实事求是；（二）失责必问、问责必严；（三）权责一致、错责相当；（四）严管和厚爱结合、激励和约束并重；（五）惩前毖后、治病救人；（六）集体决定、分清责任。', '2024-01-01 00:00:00'),

('中国共产党巡视工作条例（2024年修订）', '纪律法规', '中共中央', '2024-02-08', 1, 12000, '中国共产党巡视工作条例（2024年修订）\n\n第一条 为了坚持和加强党对巡视工作的领导，推进党的自我革命、全面从严治党，根据《中国共产党章程》，制定本条例。\n\n第二条 巡视工作是上级党组织对下级党组织履行党的领导职能责任的政治监督，根本任务是坚决维护习近平总书记党中央的核心、全党的核心地位，坚决维护以习近平同志为核心的党中央权威和集中统一领导。', '2024-01-01 00:00:00'),

('中国共产党纪律检查委员会工作条例', '纪律法规', '中共中央', '2021-12-24', 1, 14800, '中国共产党纪律检查委员会工作条例\n\n第一条 为了加强和规范党的纪律检查委员会工作，根据《中国共产党章程》，制定本条例。\n\n第二条 党的各级纪律检查委员会遵循以下原则：（一）坚持党的全面领导，坚持党中央集中统一领导；（二）坚持以人民为中心；（三）坚持民主集中制；（四）坚持严的主基调，全面从严、一严到底；（五）坚持实事求是；（六）坚持惩前毖后、治病救人。', '2024-01-01 00:00:00'),

('中国共产党党内监督条例', '纪律法规', '中共中央', '2016-10-27', 1, 11000, '中国共产党党内监督条例\n\n第一章 总则\n\n第一条 为坚持党的领导，加强党的建设，全面从严治党，强化党内监督，保持党的先进性和纯洁性，根据《中国共产党章程》，制定本条例。\n\n第二条 党内监督以马克思列宁主义、毛泽东思想、邓小平理论、"三个代表"重要思想、科学发展观为指导，深入贯彻习近平总书记系列重要讲话精神，围绕统筹推进"五位一体"总体布局和协调推进"四个全面"战略布局。\n\n第三条 党内监督没有禁区、没有例外。信任不能代替监督。各级党组织应当把信任激励同严格监督结合起来，促使党的领导干部做到有权必有责、有责要担当，用权受监督、失责必追究。', '2024-01-01 00:00:00'),

('中国共产党廉洁自律准则', '廉洁法规', '中共中央', '2015-10-18', 1, 4500, '中国共产党廉洁自律准则\n\n中国共产党全体党员和各级党员领导干部必须坚定共产主义理想和中国特色社会主义信念，必须坚持全心全意为人民服务根本宗旨，必须继承发扬党的优良传统和作风，必须自觉培养高尚道德情操，努力弘扬中华民族传统美德，廉洁自律，接受监督，永葆党的先进性和纯洁性。\n\n党员廉洁自律规范\n第一条 坚持公私分明，先公后私，克己奉公。\n第二条 坚持崇廉拒腐，清白做人，干净做事。\n第三条 坚持尚俭戒奢，艰苦朴素，勤俭节约。\n第四条 坚持吃苦在前，享受在后，甘于奉献。\n\n党员领导干部廉洁自律规范\n第五条 廉洁从政，自觉保持人民公仆本色。\n第六条 廉洁用权，自觉维护人民根本利益。\n第七条 廉洁修身，自觉提升思想道德境界。\n第八条 廉洁齐家，自觉带头树立良好家风。', '2024-01-01 00:00:00'),

('中国共产党处分违纪党员批准权限和程序规定', '纪律法规', '中共中央', '2022-09-22', 1, 8500, '中国共产党处分违纪党员批准权限和程序规定\n\n第一条 为了规范处分违纪党员的批准权限和程序，根据《中国共产党章程》和有关党内法规，制定本规定。\n\n第二条 本规定适用于各级党组织对违纪党员给予警告、严重警告、撤销党内职务、留党察看、开除党籍等纪律处分，以及对违纪党组织给予改组、解散等纪律处理的批准权限和程序。', '2024-01-01 00:00:00'),

('中国共产党组织处理规定（试行）', '纪律法规', '中共中央办公厅', '2021-03-19', 1, 6200, '中国共产党组织处理规定（试行）\n\n第一条 为了落实全面从严治党要求，规范组织处理工作，根据《中国共产党章程》和有关党内法规，制定本规定。\n\n第二条 本规定所称组织处理，是指党组织按照干部管理权限，对违纪违法、失职失责的领导干部采取的岗位、职务、资格等调整措施。组织处理措施包括停职检查、调整职务、责令辞职、免职、降职。', '2024-01-01 00:00:00'),

('纪检监察机关派驻机构工作规则', '纪律法规', '中共中央办公厅', '2022-06-22', 1, 7800, '纪检监察机关派驻机构工作规则\n\n第一条 为了规范纪检监察机关派驻机构的工作，根据《中国共产党纪律检查委员会工作条例》和《中华人民共和国监察法》，制定本规则。\n\n第二条 派驻机构是纪检监察机关的重要组成部分，由纪检监察机关统一管理，履行党的纪律检查和国家监察两项职责。', '2024-01-01 00:00:00'),

('纪检监察机关处理检举控告工作规则', '纪律法规', '中共中央办公厅', '2020-01-21', 1, 7100, '纪检监察机关处理检举控告工作规则\n\n第一条 为了规范纪检监察机关处理检举控告工作，保障党员、群众行使监督权利，维护党员、干部合法权益，根据《中国共产党章程》《中国共产党党内监督条例》等党内法规和《中华人民共和国监察法》等法律法规，制定本规则。', '2024-01-01 00:00:00'),

('中国共产党党员权利保障条例', '纪律法规', '中共中央', '2020-12-25', 1, 8900, '中国共产党党员权利保障条例（2020年修订）\n\n第一条 为了坚持党的领导，加强党的建设，发扬党内民主，保障党员权利，增强党的生机活力，根据《中国共产党章程》，制定本条例。\n\n第二条 党员应当履行党章规定的义务，不得侵犯其他党员的权利。党组织应当保障党员权利，严格规范党内政治生活，营造民主、平等的党内氛围。', '2024-01-01 00:00:00'),

('中国共产党党员教育管理工作条例', '纪律法规', '中共中央', '2019-05-06', 1, 7500, '中国共产党党员教育管理工作条例\n\n第一条 为了深入学习贯彻习近平新时代中国特色社会主义思想，加强党员教育管理工作，提高党员队伍建设质量，保持党员队伍的先进性和纯洁性，根据《中国共产党章程》和有关党内法规，制定本条例。\n\n第二条 党员教育管理是党的建设基础性经常性工作。党组织应当加强党员教育管理，引导党员坚定共产主义远大理想和中国特色社会主义共同理想。', '2024-01-01 00:00:00'),

('中国共产党党内法规解释工作规定', '纪律法规', '中共中央办公厅', '2015-07-06', 1, 4200, '中国共产党党内法规解释工作规定\n\n第一条 为了规范党内法规解释工作，维护党内法规的统一性和权威性，根据《中国共产党党内法规制定条例》，制定本规定。\n\n第二条 本规定所称党内法规解释，是指对党内法规的具体含义和适用问题所作的说明。', '2024-01-01 00:00:00'),

-- ========== 组织法规 ==========
('中国共产党中央委员会工作条例', '组织法规', '中共中央', '2020-09-30', 1, 6800, '中国共产党中央委员会工作条例\n\n第一条 为了加强党的中央委员会建设，维护党中央权威和集中统一领导，确保全党团结统一和行动一致，根据《中国共产党章程》，制定本条例。\n\n第二条 中央委员会全体会议由中央政治局召集，每年至少举行一次。中央政治局会议由中央政治局总书记召集并主持，一般每月召开一次。', '2024-01-01 00:00:00'),

('中国共产党地方委员会工作条例', '组织法规', '中共中央', '2015-12-25', 1, 8200, '中国共产党地方委员会工作条例\n\n第一条 为了落实全面从严治党要求，加强和改进党的地方委员会工作，提高党的执政能力和领导水平，根据《中国共产党章程》，制定本条例。\n\n第二条 本条例适用于党的省、自治区、直辖市，设区的市和自治州，县（旗）、自治县、不设区的市和市辖区委员会及其常务委员会。', '2024-01-01 00:00:00'),

('中国共产党党组工作条例', '组织法规', '中共中央', '2019-04-06', 1, 6500, '中国共产党党组工作条例（2019年修订）\n\n第一条 为了进一步规范和改进党组工作，坚持和加强党的全面领导，提高党的执政能力，更好发挥党总揽全局、协调各方的领导核心作用，根据《中国共产党章程》，制定本条例。\n\n第二条 党组是党在中央和地方国家机关、人民团体、经济组织、文化组织和其他非党组织的领导机关中设立的领导机构，在本单位发挥领导作用。', '2024-01-01 00:00:00'),

('中国共产党工作机关条例（试行）', '组织法规', '中共中央', '2017-03-01', 1, 5400, '中国共产党工作机关条例（试行）\n第一条 为了规范党的工作机关的设立和运行，加强党的工作机关建设，提高党的执政能力和领导水平，根据《中国共产党章程》，制定本条例。\n第二条 党的工作机关是党实施政治、思想和组织领导的政治机关，是落实党中央和地方各级党委决策部署，实施党的领导、加强党的建设、推进党的事业的执行机关。', '2024-01-01 00:00:00'),

('中国共产党支部工作条例（试行）', '组织法规', '中共中央', '2018-10-28', 1, 7800, '中国共产党支部工作条例（试行）\n\n第一章 总则\n\n第一条 为了坚持和加强党的全面领导，弘扬"支部建在连上"光荣传统，落实党要管党、全面从严治党要求，全面提升党支部组织力，强化党支部政治功能，充分发挥党支部战斗堡垒作用，巩固党长期执政的组织基础，根据《中国共产党章程》和有关党内法规，制定本条例。\n\n第二条 党支部是党的基础组织，是党组织开展工作的基本单元，是实现党的领导、加强党的建设的基本载体。', '2024-01-01 00:00:00'),

('中国共产党党员权利保障条例', '组织法规', '中共中央', '2020-12-25', 1, 8900, '中国共产党党员权利保障条例\n\n第一条 为了坚持党的领导，加强党的建设，发扬党内民主，保障党员权利，增强党的生机活力，根据《中国共产党章程》，制定本条例。\n\n第二条 党组织应当尊重党员主体地位，保障党员知情权、参与权、选举权、监督权等权利。', '2024-01-01 00:00:00'),

('党政领导干部选拔任用工作条例', '组织法规', '中共中央', '2019-03-03', 1, 13500, '党政领导干部选拔任用工作条例（2019年修订）\n\n第一章 总则\n\n第一条 为了坚持和加强党的全面领导，深入贯彻新时代党的组织路线和干部工作方针政策，落实党管干部原则，建设信念坚定、为民服务、勤政务实、敢于担当、清正廉洁的高素质专业化党政领导干部队伍，根据《中国共产党章程》等党内法规和《中华人民共和国公务员法》等有关法律法规，制定本条例。', '2024-01-01 00:00:00'),

('推进领导干部能上能下规定', '组织法规', '中共中央办公厅', '2022-09-08', 1, 5800, '推进领导干部能上能下规定（2022年修订）\n\n第一条 为了全面推进党的政治建设、思想建设、组织建设、作风建设、纪律建设，完善从严管理干部队伍制度体系，推动形成能者上、优者奖、庸者下、劣者汰的用人导向和从政环境，根据《中国共产党章程》和有关党内法规，制定本规定。', '2024-01-01 00:00:00'),

('党政领导干部考核工作条例', '组织法规', '中共中央办公厅', '2019-04-07', 1, 8200, '党政领导干部考核工作条例\n\n第一条 为了坚持和加强党的全面领导，坚持党管干部原则，建设高素质专业化党政领导干部队伍，推动各项事业发展，根据《中国共产党章程》和有关党内法规，制定本条例。\n\n第二条 本条例适用于中共中央、全国人大常委会、国务院、全国政协工作部门或者机关内设机构的领导班子和领导干部，以及上述部门或者机关下属单位的领导班子和领导干部。', '2024-01-01 00:00:00'),

('干部教育培训工作条例', '组织法规', '中共中央', '2023-09-19', 1, 9100, '干部教育培训工作条例（2023年修订）\n第一条 为了推进干部教育培训工作科学化、制度化、规范化，培养造就忠诚干净担当的高素质专业化干部队伍，根据《中国共产党章程》和有关党内法规，制定本条例。\n第二条 干部教育培训是建设高素质干部队伍的先导性、基础性、战略性工程，在推进中国特色社会主义伟大事业和党的建设新的伟大工程中具有不可替代的重要地位和作用。', '2024-01-01 00:00:00'),

('中国共产党基层组织选举工作条例', '组织法规', '中共中央', '2020-07-13', 1, 6800, '中国共产党基层组织选举工作条例\n第一条 为了深入贯彻习近平新时代中国特色社会主义思想，贯彻落实新时代党的建设总要求和新时代党的组织路线，坚持和加强党的全面领导，坚持党要管党、全面从严治党，健全党的民主集中制，完善党内选举制度，增强基层党组织政治功能和组织力，根据《中国共产党章程》和有关党内法规，制定本条例。', '2024-01-01 00:00:00'),

('中国共产党地方组织选举工作条例', '组织法规', '中共中央', '2020-12-28', 1, 8200, '中国共产党地方组织选举工作条例\n第一条 为了深入贯彻习近平新时代中国特色社会主义思想，贯彻落实新时代党的建设总要求和新时代党的组织路线，坚持和加强党的全面领导，坚持党要管党、全面从严治党，健全党的民主集中制，完善党内选举制度，加强党的地方组织建设，根据《中国共产党章程》，制定本条例。', '2024-01-01 00:00:00'),

('中国共产党全国代表大会和地方各级代表大会代表任期制规定', '组织法规', '中共中央', '2008-05-05', 1, 4100, '中国共产党全国代表大会和地方各级代表大会代表任期制规定\n第一条 为发挥党的代表大会代表作用，坚持和完善党代表大会制度，推进党内民主建设，提高党的执政能力，保持党的先进性，根据《中国共产党章程》和有关党内法规的规定，制定本规定。', '2024-01-01 00:00:00'),

('党政领导干部交流工作规定', '组织法规', '中共中央办公厅', '2006-08-06', 1, 5200, '党政领导干部交流工作规定\n第一条 为了推进党政领导干部交流工作，进一步优化领导班子结构，提高领导干部的素质和能力，加强党风廉政建设，促进经济社会发展，根据《中华人民共和国公务员法》《党政领导干部选拔任用工作条例》和有关法律法规，制定本规定。', '2024-01-01 00:00:00'),

('党政领导干部任职回避暂行规定', '组织法规', '中共中央办公厅', '2006-06-10', 1, 3800, '党政领导干部任职回避暂行规定\n第一条 为了加强对党政领导干部的管理和监督，保证领导干部公正履行职责，促进党风廉政建设，根据《中华人民共和国公务员法》和有关党内法规，制定本规定。', '2024-01-01 00:00:00'),

('党政机关公文处理工作条例', '组织法规', '中共中央办公厅、国务院办公厅', '2012-04-16', 1, 7500, '党政机关公文处理工作条例\n第一条 为了适应中国共产党机关和国家行政机关工作需要，推进党政机关公文处理工作科学化、制度化、规范化，制定本条例。\n第二条 本条例适用于各级党政机关公文处理工作。', '2024-01-01 00:00:00'),

-- ========== 监督法规 ==========
('中国共产党党内监督条例', '监督法规', '中共中央', '2016-10-27', 1, 11000, '中国共产党党内监督条例\n第一条 为坚持党的领导，加强党的建设，全面从严治党，强化党内监督，保持党的先进性和纯洁性，根据《中国共产党章程》，制定本条例。\n第二条 党内监督以马克思列宁主义、毛泽东思想、邓小平理论、"三个代表"重要思想、科学发展观为指导，深入贯彻习近平总书记系列重要讲话精神。', '2024-01-01 00:00:00'),

('中国共产党巡视工作条例', '监督法规', '中共中央', '2024-02-08', 1, 12000, '中国共产党巡视工作条例（2024年修订）\n第一条 为了坚持和加强党对巡视工作的领导，推进党的自我革命、全面从严治党，根据《中国共产党章程》，制定本条例。\n第二条 巡视工作是上级党组织对下级党组织履行党的领导职能责任的政治监督，根本任务是坚决维护习近平总书记党中央的核心、全党的核心地位。', '2024-01-01 00:00:00'),

('关于领导干部报告个人有关事项的规定', '监督法规', '中共中央办公厅、国务院办公厅', '2017-04-10', 1, 6500, '关于领导干部报告个人有关事项的规定\n第一条 为加强对领导干部的管理和监督，促进领导干部廉洁从政，根据《中国共产党章程》、党内有关规定和国家有关法律法规，制定本规定。\n第二条 本规定所称领导干部包括：（一）各级党的机关、人大机关、行政机关、政协机关、审判机关、检察机关、民主党派机关中县处级副职以上（含县处级副职）的干部。', '2024-01-01 00:00:00'),

('领导干部干预司法活动、插手具体案件处理的记录、通报和责任追究规定', '监督法规', '中共中央办公厅、国务院办公厅', '2015-03-18', 1, 4200, '领导干部干预司法活动、插手具体案件处理的记录、通报和责任追究规定\n第一条 为贯彻落实《中共中央关于全面推进依法治国若干重大问题的决定》有关要求，防止领导干部干预司法活动、插手具体案件处理，确保司法机关依法独立公正行使职权，根据宪法法律规定，结合司法工作实际，制定本规定。', '2024-01-01 00:00:00'),

('关于防止干部"带病提拔"的意见', '监督法规', '中共中央办公厅', '2016-08-29', 1, 5100, '关于防止干部"带病提拔"的意见\n落实全面从严治党要求，坚持把纪律挺在前面，严格干部选拔任用工作监督，着力解决干部选拔任用中"带病提拔"问题，营造风清气正用人环境，根据《党政领导干部选拔任用工作条例》《中国共产党党内监督条例》等党内法规，现提出如下意见。', '2024-01-01 00:00:00'),

('关于在深化国有企业改革中坚持党的领导加强党的建设的若干意见', '监督法规', '中共中央办公厅', '2015-09-20', 1, 4800, '关于在深化国有企业改革中坚持党的领导加强党的建设的若干意见\n坚持党的领导、加强党的建设是国有企业的"根"和"魂"。在深化国有企业改革中坚持党的领导加强党的建设，是落实全面从严治党要求的必然选择，是推进国有企业改革发展的根本保证。', '2024-01-01 00:00:00'),

('中国共产党党务公开条例（试行）', '监督法规', '中共中央', '2017-12-20', 1, 6200, '中国共产党党务公开条例（试行）\n第一条 为了贯彻落实党的十九大精神，推动全面从严治党向纵深发展，加强和规范党务公开工作，发展党内民主，强化党内监督，使广大党员更好地了解和参与党内事务，动员组织人民群众贯彻落实好党的理论和路线方针政策，提高党的执政能力和领导水平，根据《中国共产党章程》，制定本条例。', '2024-01-01 00:00:00'),

('地方党政领导干部安全生产责任制规定', '监督法规', '中共中央办公厅、国务院办公厅', '2018-04-08', 1, 5600, '地方党政领导干部安全生产责任制规定\n第一条 为了加强地方各级党委和政府对安全生产工作的领导，健全落实安全生产责任制，树立安全发展理念，根据《中华人民共和国安全生产法》《中华人民共和国突发事件应对法》等法律法规和《中国共产党地方委员会工作条例》《中国共产党问责条例》等党内法规，制定本规定。', '2024-01-01 00:00:00'),

('防范和惩治统计造假、弄虚作假督查工作规定', '监督法规', '国家统计局', '2019-10-11', 1, 3900, '防范和惩治统计造假、弄虚作假督查工作规定\n第一条 为了深入贯彻落实党中央、国务院关于防范和惩治统计造假、弄虚作假的重要决策部署，切实提高统计数据质量，根据《中华人民共和国统计法》及其实施条例、《中国共产党纪律处分条例》《中国共产党问责条例》等有关法律法规和党内法规，制定本规定。', '2024-01-01 00:00:00'),

-- ========== 廉洁法规 ==========
('中国共产党廉洁自律准则', '廉洁法规', '中共中央', '2015-10-18', 1, 4500, '中国共产党廉洁自律准则\n中国共产党全体党员和各级党员领导干部必须坚定共产主义理想和中国特色社会主义信念，必须坚持全心全意为人民服务根本宗旨。\n\n党员廉洁自律规范\n第一条 坚持公私分明，先公后私，克己奉公。\n第二条 坚持崇廉拒腐，清白做人，干净做事。\n第三条 坚持尚俭戒奢，艰苦朴素，勤俭节约。\n第四条 坚持吃苦在前，享受在后，甘于奉献。', '2024-01-01 00:00:00'),

('中国共产党纪律处分条例（2023年）—违反廉洁纪律', '廉洁法规', '中共中央', '2023-12-19', 1, 8200, '违反廉洁纪律行为的处分\n\n利用职权或者职务上的影响，违反有关规定占用公物归个人使用，时间超过六个月，情节较重的，给予警告或者严重警告处分；情节严重的，给予撤销党内职务处分。\n\n违反有关规定组织、参加用公款支付的宴请、高消费娱乐、健身活动，或者用公款购买赠送或者发放礼品、消费卡等，对直接责任者和领导责任者，给予警告或者严重警告处分。', '2024-01-01 00:00:00'),

('关于改进工作作风、密切联系群众的八项规定', '廉洁法规', '中共中央政治局', '2012-12-04', 1, 3500, '关于改进工作作风、密切联系群众的八项规定\n\n改进调查研究，到基层调研要深入了解真实情况，向群众学习、向实践学习。要轻车简从、减少陪同、简化接待，不张贴悬挂标语横幅。精简会议活动，切实改进会风，严格控制以中央名义召开的各类全国性会议和举行的重大活动。精简文件简报，切实改进文风，没有实质内容、可发可不发的文件、简报一律不发。规范出访活动，改进警卫工作，改进新闻报道，严格文稿发表，厉行勤俭节约。', '2024-01-01 00:00:00'),

('党政机关厉行节约反对浪费条例', '廉洁法规', '中共中央、国务院', '2013-11-18', 1, 7800, '党政机关厉行节约反对浪费条例\n第一条 为了进一步弘扬艰苦奋斗、勤俭节约的优良作风，推进党政机关厉行节约反对浪费，建设节约型机关，根据国家有关法律法规和中央有关规定，制定本条例。\n第二条 本条例适用于党的机关、人大机关、行政机关、政协机关、审判机关、检察机关，以及工会、共青团、妇联等人民团体和参照公务员法管理的事业单位。', '2024-01-01 00:00:00'),

('党政机关办公用房管理办法', '廉洁法规', '国家机关事务管理局、中共中央直属机关事务管理局', '2017-12-05', 1, 6100, '党政机关办公用房管理办法\n第一条 为了规范党政机关办公用房管理，合理配置办公用房资源，提高办公用房使用效益，降低行政运行成本，促进党风廉政建设，根据《党政机关厉行节约反对浪费条例》等有关规定，制定本办法。', '2024-01-01 00:00:00'),

('党政机关公务用车管理办法', '廉洁法规', '国家机关事务管理局、中共中央直属机关事务管理局', '2017-12-05', 1, 5400, '党政机关公务用车管理办法\n第一条 为了进一步规范党政机关公务用车管理，有效保障公务出行，降低行政成本，促进党风廉政建设，根据《党政机关厉行节约反对浪费条例》《机关事务管理条例》等有关规定，制定本办法。', '2024-01-01 00:00:00'),

('党政机关国内公务接待管理规定', '廉洁法规', '中共中央办公厅、国务院办公厅', '2013-12-08', 1, 4200, '党政机关国内公务接待管理规定\n第一条 为了规范党政机关国内公务接待管理，厉行勤俭节约，反对铺张浪费，加强党风廉政建设，根据《党政机关厉行节约反对浪费条例》规定，制定本规定。\n第二条 本规定适用于各级党的机关、人大机关、行政机关、政协机关、审判机关、检察机关，以及工会、共青团、妇联等人民团体和参照公务员法管理的事业单位。', '2024-01-01 00:00:00'),

-- ========== 人事/干部管理 ==========
('公务员职务与职级并行规定', '干部管理', '中共中央办公厅', '2019-03-27', 1, 7200, '公务员职务与职级并行规定\n第一条 为了深化公务员分类改革，推行公务员职务与职级并行、职级与待遇挂钩制度，健全公务员激励保障机制，建设信念坚定、为民服务、勤政务实、敢于担当、清正廉洁的高素质专业化公务员队伍，根据《中华人民共和国公务员法》等有关法律法规，制定本规定。', '2024-01-01 00:00:00'),

('公务员录用规定', '干部管理', '中共中央组织部', '2019-11-25', 1, 6500, '公务员录用规定\n第一条 为了规范公务员录用工作，保证新录用公务员的基本素质，建设信念坚定、为民服务、勤政务实、敢于担当、清正廉洁的高素质专业化公务员队伍，根据《中华人民共和国公务员法》和有关法律法规，制定本规定。', '2024-01-01 00:00:00'),

('公务员考核规定', '干部管理', '中共中央组织部', '2020-12-28', 1, 5800, '公务员考核规定\n第一条 为了准确评价公务员的德才表现和工作实绩，规范公务员考核工作，建设信念坚定、为民服务、勤政务实、敢于担当、清正廉洁的高素质专业化公务员队伍，根据《中华人民共和国公务员法》和有关法律法规，制定本规定。', '2024-01-01 00:00:00'),

('公务员职务任免与职务升降规定（试行）', '干部管理', '中共中央组织部', '2008-07-16', 1, 6100, '公务员职务任免与职务升降规定（试行）\n第一条 为健全公务员职务任免与职务升降制度，完善公务员职务管理，规范公务员职务任免与职务升降工作，根据公务员法和有关法律、法规，制定本规定。', '2024-01-01 00:00:00'),

('新录用公务员试用期管理办法（试行）', '干部管理', '中共中央组织部、人力资源和社会保障部', '2011-05-25', 1, 4200, '新录用公务员试用期管理办法（试行）\n第一条 为了规范新录用公务员试用期管理工作，完善公务员录用制度，保证新录用公务员的基本素质，根据《中华人民共和国公务员法》和《公务员录用规定（试行）》等有关法律法规，制定本办法。', '2024-01-01 00:00:00'),

('公务员辞退规定（试行）', '干部管理', '中共中央组织部、人力资源和社会保障部', '2009-07-16', 1, 4800, '公务员辞退规定（试行）\n第一条 为保障公务员的合法权益，规范公务员辞退工作，根据公务员法，制定本规定。\n第二条 辞退公务员，是指机关依照法律、法规规定，解除与公务员的任用关系。', '2024-01-01 00:00:00'),

('公务员培训规定', '干部管理', '中共中央组织部', '2019-11-25', 1, 5500, '公务员培训规定\n第一条 为了全面提高公务员素质和能力，建设信念坚定、为民服务、勤政务实、敢于担当、清正廉洁的高素质专业化公务员队伍，根据《中华人民共和国公务员法》和有关法律法规，制定本规定。', '2024-01-01 00:00:00'),

('公务员奖励规定', '干部管理', '中共中央组织部', '2020-12-28', 1, 5200, '公务员奖励规定\n第一条 为了激励公务员担当作为，建设信念坚定、为民服务、勤政务实、敢于担当、清正廉洁的高素质专业化公务员队伍，根据《中华人民共和国公务员法》和有关法律法规，制定本规定。', '2024-01-01 00:00:00'),

('参照公务员法管理的单位审批办法', '干部管理', '中共中央组织部、人事部', '2006-04-09', 1, 3600, '参照公务员法管理的单位审批办法\n第一条 为规范参照公务员法管理的单位审批工作，根据《中华人民共和国公务员法》，制定本办法。\n第二条 法律、法规授权的具有公共事务管理职能的事业单位，经批准参照公务员法管理。', '2024-01-01 00:00:00'),

-- ========== 宣传法规 ==========
('中国共产党宣传工作条例', '宣传法规', '中共中央', '2019-06-29', 1, 8200, '中国共产党宣传工作条例\n第一条 为了加强党对宣传工作的全面领导，推动宣传工作适应新时代要求，根据《中国共产党章程》和有关党内法规，制定本条例。\n第二条 宣传工作是党的一项极端重要的工作，是中国共产党领导人民不断夺取革命、建设、改革胜利的优良传统和政治优势。', '2024-01-01 00:00:00'),

('党委（党组）意识形态工作责任制实施办法', '宣传法规', '中共中央办公厅', '2015-10-03', 1, 4500, '党委（党组）意识形态工作责任制实施办法\n第一条 意识形态工作是党的一项极端重要的工作，关乎旗帜、关乎道路、关乎国家政治安全。按照属地管理、分级负责和谁主管谁负责的原则，各级党委（党组）领导班子对本地区本部门本单位意识形态工作负主体责任。', '2024-01-01 00:00:00'),

('党委（党组）网络安全工作责任制实施办法', '宣传法规', '中共中央办公厅', '2017-08-15', 1, 3800, '党委（党组）网络安全工作责任制实施办法\n第一条 按照权责一致的原则，谁主管谁负责、谁运行谁负责、谁使用谁负责，党委（党组）对本地区本部门网络安全工作负主体责任。领导班子主要负责人是网络安全工作第一责任人。', '2024-01-01 00:00:00'),

('关于进一步加强和改进舆论监督工作的意见', '宣传法规', '中共中央办公厅', '2005-04-05', 1, 4100, '关于进一步加强和改进舆论监督工作的意见\n舆论监督是社会发展的产物，是新闻媒体的重要职责。进一步发挥新闻舆论监督的作用，对于推进社会主义民主政治建设，构建社会主义和谐社会，具有重要意义。', '2024-01-01 00:00:00'),

-- ========== 统一战线 ==========
('中国共产党统一战线工作条例（2025年修订）', '统战法规', '中共中央', '2025-01-01', 1, 10500, '中国共产党统一战线工作条例（2025年修订）\n第一条 为了加强和规范统一战线工作，巩固和发展最广泛的爱国统一战线，根据《中国共产党章程》，制定本条例。\n第二条 本条例所称统一战线，是指中国共产党领导的、以工农联盟为基础的，包括全体社会主义劳动者、社会主义事业建设者、拥护社会主义的爱国者、拥护祖国统一和致力于中华民族伟大复兴的爱国者的联盟。', '2024-01-01 00:00:00'),

('社会主义学院工作条例', '统战法规', '中共中央、国务院', '2018-12-25', 1, 5800, '社会主义学院工作条例\n第一条 为了巩固和发展最广泛的爱国统一战线，加强党对社会主义学院的领导，规范社会主义学院工作，根据《中国共产党章程》《中国共产党统一战线工作条例》等党内法规和《中华人民共和国公务员法》等法律，制定本条例。', '2024-01-01 00:00:00'),

-- ========== 人事管理 ==========
('中国共产党党内功勋荣誉表彰条例', '其他', '中共中央', '2017-08-08', 1, 6200, '中国共产党党内功勋荣誉表彰条例\n第一条 为了规范党内功勋荣誉表彰工作，弘扬正气，激励先进，根据《中国共产党章程》和有关党内法规，制定本条例。\n第二条 本条例所称党内功勋荣誉表彰，是指对在中国特色社会主义事业中作出突出贡献的党员、党组织和党务工作者给予表彰奖励。', '2024-01-01 00:00:00'),

('中国共产党党内关怀帮扶办法', '其他', '中共中央办公厅', '2019-11-15', 1, 4200, '中国共产党党内关怀帮扶办法\n第一条 为了坚持和加强党的全面领导，增强党的凝聚力、战斗力，建立健全党内关怀帮扶长效机制，关心爱护党员，激励广大党员充分发挥先锋模范作用，根据《中国共产党章程》和有关党内法规，制定本办法。', '2024-01-01 00:00:00'),

('中国共产党党内法规和规范性文件备案规定', '其他', '中共中央办公厅', '2012-06-04', 1, 4800, '中国共产党党内法规和规范性文件备案规定\n第一条 为了规范党内法规和规范性文件备案工作，保证党内法规和规范性文件同党章和党的理论、路线、方针、政策相一致，同宪法和法律相一致，维护党内法规制度体系的统一性和权威性，根据《中国共产党党内法规制定条例》，制定本规定。', '2024-01-01 00:00:00'),

('中国共产党重大事项请示报告条例', '其他', '中共中央', '2019-01-31', 1, 7800, '中国共产党重大事项请示报告条例\n第一条 为了加强和规范重大事项请示报告工作，严明党的政治纪律、组织纪律和工作纪律，保证全党全国服从党中央、政令畅通，根据《中国共产党章程》《关于新形势下党内政治生活的若干准则》等党内法规，制定本条例。', '2024-01-01 00:00:00'),

('中国共产党党内法规和规范性文件汇编工作规定', '其他', '中共中央办公厅', '2015-07-06', 1, 3500, '中国共产党党内法规和规范性文件汇编工作规定\n第一条 为了规范党内法规和规范性文件汇编工作，保证汇编质量，维护党内法规和规范性文件的统一性和权威性，根据《中国共产党党内法规制定条例》，制定本规定。', '2024-01-01 00:00:00'),

-- ========== 农村基层 ==========
('中国共产党农村基层组织工作条例', '农村基层', '中共中央', '2019-01-10', 1, 8500, '中国共产党农村基层组织工作条例（2019年修订）\n第一条 农村工作在党和国家事业全局中具有重要战略地位，是全党工作的重中之重。为了坚持和加强党对农村工作的全面领导，提高党的农村基层组织建设质量，为新时代乡村全面振兴提供坚强政治和组织保证，根据《中国共产党章程》，制定本条例。\n第二条 乡镇党的委员会和村党组织（村党支部或党总支、党委）是党在农村的基层组织，是党在农村全部工作和战斗力的基础，全面领导乡镇、村的各类组织和各项工作。', '2024-01-01 00:00:00'),

('中国共产党地方各级代表大会代表任期制实施办法', '农村基层', '中共中央', '2008-07-14', 1, 4500, '中国共产党地方各级代表大会代表任期制实施办法\n第一条 为充分发挥党的地方各级代表大会代表作用，坚持和完善党代表大会制度，推进党内民主建设，提高党的执政能力，保持党的先进性，根据《中国共产党章程》和有关党内法规的规定，制定本办法。', '2024-01-01 00:00:00'),

-- ========== 国有企业 ==========
('关于在深化国有企业改革中坚持党的领导加强党的建设的若干意见', '国有企业', '中共中央办公厅', '2015-09-20', 1, 4800, '关于在深化国有企业改革中坚持党的领导加强党的建设的若干意见\n坚持党的领导、加强党的建设是我国国有企业的光荣传统，是国有企业的"根"和"魂"，是我国国有企业的独特优势。', '2024-01-01 00:00:00'),

('国有企业领导人员廉洁从业若干规定', '国有企业', '中共中央办公厅、国务院办公厅', '2009-07-12', 1, 5500, '国有企业领导人员廉洁从业若干规定\n第一条 为规范国有企业领导人员廉洁从业行为，加强国有企业反腐倡廉建设，维护国家和出资人利益，促进国有企业科学发展，依据国家有关法律法规和党内法规，制定本规定。', '2024-01-01 00:00:00'),

('关于中央企业领导人员廉洁自律"七不准"的要求', '国有企业', '中共中央纪委', '2007-04-12', 1, 3200, '关于中央企业领导人员廉洁自律"七不准"的要求\n一、不准利用职务上的便利通过同业经营或关联交易为本人或特定关系人谋取利益。二、不准相互为对方及其配偶、子女和其他特定关系人从事营利性经营活动提供便利条件。三、不准在企业资产整合、引入战略投资者等过程中利用职权谋取私利。', '2024-01-01 00:00:00'),

-- ========== 党务管理 ==========
('关于中国共产党党费收缴、使用和管理的规定', '党务管理', '中共中央组织部', '2008-02-04', 1, 5200, '关于中国共产党党费收缴、使用和管理的规定\n第一条 按月交纳党费是党员应尽的责任和义务，是党员关心党的事业的一种表现。按照党章规定向党组织交纳党费，是共产党员必须具备的起码条件。\n第二条 党员交纳党费的比例为：每月工资收入（税后）在3000元以下（含3000元）者，交纳月工资收入的0.5%；3000元以上至5000元（含5000元）者，交纳1%；5000元以上至10000元（含10000元）者，交纳1.5%。', '2024-01-01 00:00:00'),

('中国共产党发展党员工作细则', '党务管理', '中共中央组织部', '2014-05-28', 1, 7800, '中国共产党发展党员工作细则（2014年修订）\n第一条 为了规范发展党员工作，保证新发展的党员质量，保持党的先进性和纯洁性，根据《中国共产党章程》和党内有关规定，制定本细则。\n第二条 党的基层组织应当把吸收具有共产主义觉悟的先进分子入党，作为一项经常性重要工作。发展党员工作应当贯彻控制总量、优化结构、提高质量、发挥作用的总要求。', '2024-01-01 00:00:00'),

('中国共产党党内选举工作手册（相关规定）', '党务管理', '中共中央组织部', '2020-12-28', 1, 4500, '中国共产党党内选举工作的相关规定\n党内选举是党内民主的基本实现形式。党组织应当按照民主集中制原则，开展党内选举工作，保障党员的民主权利。选举应当体现选举人的意志，采用无记名投票的方式。', '2024-01-01 00:00:00'),

('中国共产党党员权利保障条例相关实施办法', '党务管理', '中共中央', '2020-12-25', 1, 5100, '中国共产党党员权利保障条例相关实施办法\n党组织应当切实保障党员各项权利的实现。对于任何侵犯党员权利的行为，都应当予以追究。党员应当正确行使权利，不得侵犯其他党员的权利。', '2024-01-01 00:00:00'),

('中国共产党党员网络行为规定', '党务管理', '中共中央办公厅', '2024-01-15', 1, 4200, '中国共产党党员网络行为规定\n第一条 为了规范党员网络行为，发挥党员在网络空间的先锋模范作用，营造风清气正的网络环境，根据《中国共产党章程》《中国共产党纪律处分条例》等党内法规，制定本规定。\n第二条 党员在网络空间应当遵守国家法律法规和党的纪律，坚持正确政治方向，自觉维护党的形象。', '2024-01-01 00:00:00'),

('中国共产党不合格党员组织处置办法', '党务管理', '中共中央办公厅', '2023-12-18', 1, 4800, '中国共产党不合格党员组织处置办法\n第一条 为了深入贯彻习近平新时代中国特色社会主义思想，贯彻落实全面从严治党要求，做好不合格党员组织处置工作，根据《中国共产党章程》和《中国共产党纪律处分条例》等有关党内法规，制定本办法。', '2024-01-01 00:00:00'),

('中国共产党党内功勋荣誉表彰工作程序规定', '党务管理', '中共中央办公厅', '2023-07-12', 1, 3900, '中国共产党党内功勋荣誉表彰工作程序规定\n第一条 为了规范党内功勋荣誉表彰工作程序，保证党内功勋荣誉表彰质量，根据《中国共产党党内功勋荣誉表彰条例》，制定本规定。', '2024-01-01 00:00:00'),

('关于建立健全村务监督委员会的指导意见', '基层治理', '中共中央办公厅、国务院办公厅', '2017-12-04', 1, 4200, '关于建立健全村务监督委员会的指导意见\n建立健全村务监督委员会，是完善基层民主政治建设的重要内容，是加强农村基层党风廉政建设的重要举措。', '2024-01-01 00:00:00'),

('中国共产党党员教育培训工作规划（2024-2028年）', '党务管理', '中共中央办公厅', '2024-01-11', 1, 5800, '中国共产党党员教育培训工作规划（2024-2028年）\n为深入贯彻习近平新时代中国特色社会主义思想，全面落实党的二十大和二十届二中全会精神，进一步做好党员教育培训工作，根据《中国共产党章程》和有关党内法规，制定本规划。', '2024-01-01 00:00:00'),

('中国共产党党组讨论和决定党员处分事项工作程序规定（试行）', '党务管理', '中共中央办公厅', '2018-12-16', 1, 4100, '中国共产党党组讨论和决定党员处分事项工作程序规定（试行）\n第一条 为了贯彻落实党的十八届六中全会精神，规范党组讨论和决定党员处分事项工作程序，根据《中国共产党章程》等党内法规，制定本规定。', '2024-01-01 00:00:00'),

('中国共产党处分违纪党员批准权限和程序规定', '党务管理', '中共中央', '2022-09-22', 1, 8500, '中国共产党处分违纪党员批准权限和程序规定\n第一条 为了规范处分违纪党员的批准权限和程序，根据《中国共产党章程》和有关党内法规，制定本规定。', '2024-01-01 00:00:00'),

('关于党的基层组织实行党务公开的意见', '党务管理', '中共中央', '2010-09-15', 1, 3800, '关于党的基层组织实行党务公开的意见\n党务公开是指党的组织将其实施党的领导活动、加强党的建设工作的有关事务，按规定在党内或者向党外公开。', '2024-01-01 00:00:00'),

('关于进一步加强党员组织关系管理的意见', '党务管理', '中共中央组织部', '2004-11-01', 1, 4100, '关于进一步加强党员组织关系管理的意见\n党员组织关系是指党员对党的基层组织的隶属关系。按照党章规定，每个党员不论职务高低，都必须编入党的一个支部、小组或其他特定组织，参加党的组织生活，接受党内外群众的监督。', '2024-01-01 00:00:00'),

('关于建立健全党员承诺践诺制度的意见', '党务管理', '中共中央组织部', '2019-08-15', 1, 3200, '关于建立健全党员承诺践诺制度的意见\n建立党员承诺践诺制度，是推进"两学一做"学习教育常态化制度化的重要举措，是发挥党员先锋模范作用的有效途径。', '2024-01-01 00:00:00'),

('中国共产党党徽党旗条例', '党务管理', '中共中央', '2021-06-26', 1, 5200, '中国共产党党徽党旗条例\n第一条 为了规范党徽党旗制作、使用、管理，充分发挥党徽党旗的政治功能，增强党的凝聚力、战斗力，激发党员党的意识，根据《中国共产党章程》，制定本条例。', '2024-01-01 00:00:00'),

('中国共产党党员网络行为规定', '网络党建', '中共中央办公厅', '2024-01-15', 1, 4200, '中国共产党党员网络行为规定\n第一条 为了规范党员网络行为，发挥党员在网络空间的先锋模范作用，营造风清气正的网络环境，根据《中国共产党章程》《中国共产党纪律处分条例》等党内法规，制定本规定。\n第二条 党员在网络空间应当遵守国家法律法规和党的纪律，坚持正确政治方向，自觉维护党的形象。', '2024-01-01 00:00:00'),

('关于加强网络文明建设的意见', '网络党建', '中共中央办公厅、国务院办公厅', '2021-09-14', 1, 4800, '关于加强网络文明建设的意见\n加强网络文明建设，是推进社会主义精神文明建设、提高社会文明程度的必然要求，是适应社会信息化进程、建设网络强国的迫切需要。', '2024-01-01 00:00:00');

